revision.text:
.side-box {
	background-color: #f9f9f9;
	border: 1px solid #aaa;
	font-size: 88%;
	line-height: 1.25em;
	box-sizing: border-box;
}

.side-box-abovebelow {
	padding: 0.25em 0.9em;
}

.side-box-image {
	text-align: center;
}

.side-box-imageright {
	text-align: center;
}

.side-box-text {
	padding: 0.25em 0.9em;
}

@media (min-width: 500px) {
	.side-box-flex {
		display: flex;
	}
}

@media (min-width: 720px) {
	.side-box {
		clear: right;
		float: right;
		margin: 4px 0 4px 1em;
		width: 238px;
	}
}

.side-box {
	background-color: #f9f9f9;
	border: 1px solid #aaa;
	font-size: 88%;
	line-height: 1.25em;
	box-sizing: border-box;
}

.side-box-abovebelow,
.side-box-text {
	padding: 0.25em 0.9em;
}

.side-box-image {
	/* @noflip */
	padding: 2px 0 2px 0.9em;
	text-align: center;
}

.side-box-imageright {
	/* @noflip */
	padding: 2px 0.9em 2px 0;
	text-align: center;
}

/* roughly the skin's sidebar + size of side box */
@media (min-width: 500px) {
	.side-box-flex {
		display: flex;
	}

	.side-box-text {
		flex: 1;
	}
}

@media (min-width: 720px) {
	.side-box {
		width: 238px;
	}

	.side-box-right {
		/* @noflip */
		clear: right;
		/* @noflip */
		float: right;
		/* @noflip */
		margin: 4px 0 4px 1em;
	}

	/* derives from mbox classes, which do not float left in mbox-small-left
	 * so far as I can tell, that was a deliberate decision
	 */
	.side-box-left {
		/* @noflip */
		margin: 4px 1em 4px 0;
	}
}

